import java.util.Scanner;

public class BufferOverflowExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");

        String name = scanner.nextLine();

        // Ensure that the input string does not exceed the buffer size
        if (name.length() > 10) {
            System.out.println("Input string exceeds buffer size. Please enter a shorter name.");
            return;
        }

        char[] buffer = new char[10];

        // Copy the input string into a fixed size buffer
        name.getChars(0, Math.min(name.length(), buffer.length), buffer, 0);

        // Properly create a String from the buffer to avoid potential buffer overflow
        System.out.println("Hello, " + new String(buffer).trim());
    }
}

